SELECT client_id, COUNT(payment_id) AS total_payments
FROM payments
GROUP BY client_id;

SELECT SUM(amount) AS total_revenue
FROM payments
WHERE client_id = 1 AND date BETWEEN '2020-01-01' AND '2021-12-31';

SELECT SUM(amount) AS total_revenue
FROM payments
WHERE date LIKE '2023-04-%';

SELECT claim_status 
FROM garanty_claims 
WHERE claim_status = 'approved';
